 22	/*! \file s1ap_eNB_decoder.c
 23	 * \brief s1ap pdu decode procedures for eNB
 24	 * \author Sebastien ROUX and Navid Nikaein
 25	 * \email navid.nikaein@eurecom.fr
 26	 * \date 2013 - 2015
 27	 * \version 0.1
 28	 */
