 30	#include <stdio.h>
 31	
 32	#include "assertions.h"
 33	
 34	#include "intertask_interface.h"
 35	
 36	#include "s1ap_common.h"
 37	#include "s1ap_eNB_decoder.h"
 38	
 39	static int s1ap_eNB_decode_initiating_message(S1AP_S1AP_PDU_t *pdu) {
 40	  asn_encode_to_new_buffer_result_t res = { NULL, {0, NULL, NULL} };
 41	  DevAssert(pdu != NULL);
 42	
 43	  switch(pdu->choice.initiatingMessage.procedureCode) {
 44	    case S1AP_ProcedureCode_id_downlinkNASTransport:
 45	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 46	      free(res.buffer);
 47	      break;
 48	
 49	    case S1AP_ProcedureCode_id_InitialContextSetup:
 50	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 51	      free(res.buffer);
 52	      break;
 53	
 54	    case S1AP_ProcedureCode_id_UEContextRelease:
 55	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 56	      free(res.buffer);
 57	      break;
 58	
 59	    case S1AP_ProcedureCode_id_Paging:
 60	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 61	      S1AP_INFO("Paging initiating message\n");
 62	      free(res.buffer);
 63	      break;
 64	
 65	    case S1AP_ProcedureCode_id_E_RABSetup:
 66	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 67	      free(res.buffer);
 68	      S1AP_INFO("E_RABSetup initiating message\n");
 69	      break;
 70	
 71	    case S1AP_ProcedureCode_id_E_RABModify:
 72	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 73	      free(res.buffer);
 74	      S1AP_INFO("E_RABModify initiating message\n");
 75	      break;
 76	
 77	    case S1AP_ProcedureCode_id_E_RABRelease:
 78	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 79	      free(res.buffer);
 80	      S1AP_INFO("TODO E_RABRelease initiating message\n");
 81	      break;
 82	
 83	    case S1AP_ProcedureCode_id_ErrorIndication:
 84	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
 85	      free(res.buffer);
 86	      S1AP_INFO("TODO ErrorIndication initiating message\n");
 87	      break;
 88	
 89	    default:
 90	      S1AP_ERROR("Unknown procedure ID (%d) for initiating message\n",
 91	                 (int)pdu->choice.initiatingMessage.procedureCode);
 92	      return -1;
 93	  }
 94	
 95	  return 0;
 96	}
 97	
 98	static int s1ap_eNB_decode_successful_outcome(S1AP_S1AP_PDU_t *pdu) {
 99	  asn_encode_to_new_buffer_result_t res = { NULL, {0, NULL, NULL} };
100	  DevAssert(pdu != NULL);
101	
102	  switch(pdu->choice.successfulOutcome.procedureCode) {
103	    case S1AP_ProcedureCode_id_S1Setup:
104	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
105	      free(res.buffer);
106	      break;
107	
108	    case S1AP_ProcedureCode_id_PathSwitchRequest:
109	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
110	      free(res.buffer);
111	      break;
112	
113	    case S1AP_ProcedureCode_id_E_RABModificationIndication:
114	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
115	      free(res.buffer);
116	      break;
117	
118	
119	    default:
120	      S1AP_ERROR("Unknown procedure ID (%d) for successfull outcome message\n",
121	                 (int)pdu->choice.successfulOutcome.procedureCode);
122	      return -1;
123	  }
124	
125	  return 0;
126	}
127	
128	static int s1ap_eNB_decode_unsuccessful_outcome(S1AP_S1AP_PDU_t *pdu) {
129	  asn_encode_to_new_buffer_result_t res = { NULL, {0, NULL, NULL} };
130	  DevAssert(pdu != NULL);
131	
132	  switch(pdu->choice.unsuccessfulOutcome.procedureCode) {
133	    case S1AP_ProcedureCode_id_S1Setup:
134	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
135	      free(res.buffer);
136	      break;
137	   case S1AP_ProcedureCode_id_PathSwitchRequest:
138	      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
139	      free(res.buffer);
140	      break;
141	
142	    default:
143	      S1AP_ERROR("Unknown procedure ID (%d) for unsuccessfull outcome message\n",
144	                 (int)pdu->choice.unsuccessfulOutcome.procedureCode);
145	      return -1;
146	  }
147	
148	  return 0;
149	}
150	
151	int s1ap_eNB_decode_pdu(S1AP_S1AP_PDU_t *pdu, const uint8_t *const buffer,
152	                        const uint32_t length) {
153	  asn_dec_rval_t dec_ret;
154	  DevAssert(pdu != NULL);
155	  DevAssert(buffer != NULL);
156	  dec_ret = aper_decode(NULL,
157	                        &asn_DEF_S1AP_S1AP_PDU,
158	                        (void **)&pdu,
159	                        buffer,
160	                        length,
161	                        0,
162	                        0);
163	
164	  if (dec_ret.code != RC_OK) {
165	    S1AP_ERROR("Failed to decode pdu\n");
166	    return -1;
167	  }
168	
169	  switch(pdu->present) {
170	    case S1AP_S1AP_PDU_PR_initiatingMessage:
171	      return s1ap_eNB_decode_initiating_message(pdu);
172	
173	    case S1AP_S1AP_PDU_PR_successfulOutcome:
174	      return s1ap_eNB_decode_successful_outcome(pdu);
175	
176	    case S1AP_S1AP_PDU_PR_unsuccessfulOutcome:
177	      return s1ap_eNB_decode_unsuccessful_outcome(pdu);
178	
179	    default:
180	      S1AP_DEBUG("Unknown presence (%d) or not implemented\n", (int)pdu->present);
181	      break;
182	  }
183	
184	  return -1;
185	}

