static int s1ap_eNB_decode_initiating_message(S1AP_S1AP_PDU_t *pdu) {
  asn_encode_to_new_buffer_result_t res = { NULL, {0, NULL, NULL} };
  DevAssert(pdu != NULL);

  switch(pdu->choice.initiatingMessage.procedureCode) {
    case S1AP_ProcedureCode_id_downlinkNASTransport:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for downlinkNASTransport\n");
        return -1;
      }
      break;

    case S1AP_ProcedureCode_id_InitialContextSetup:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for InitialContextSetup\n");
        return -1;
      }
      break;

    case S1AP_ProcedureCode_id_UEContextRelease:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for UEContextRelease\n");
        return -1;
      }
      break;

    case S1AP_ProcedureCode_id_Paging:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        S1AP_INFO("Paging initiating message\n");
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for Paging\n");
        return -1;
      }
      break;

    case S1AP_ProcedureCode_id_E_RABSetup:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        S1AP_INFO("E_RABSetup initiating message\n");
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for E_RABSetup\n");
        return -1;
      }
      break;

    case S1AP_ProcedureCode_id_E_RABModify:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        S1AP_INFO("E_RABModify initiating message\n");
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for E_RABModify\n");
        return -1;
      }
      break;

    case S1AP_ProcedureCode_id_E_RABRelease:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        S1AP_INFO("TODO E_RABRelease initiating message\n");
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for E_RABRelease\n");
        return -1;
      }
      break;

    case S1AP_ProcedureCode_id_ErrorIndication:
      res = asn_encode_to_new_buffer(NULL, ATS_CANONICAL_XER, &asn_DEF_S1AP_S1AP_PDU, pdu);
      if (res.result.encoded > 0) {
        S1AP_INFO("TODO ErrorIndication initiating message\n");
        free(res.buffer);
      } else {
        S1AP_ERROR("Failed to encode initiating message for ErrorIndication\n");
        return -1;
      }
      break;

    default:
      S1AP_ERROR("Unknown procedure ID (%d) for initiating message\n",
                 (int)pdu->choice.initiatingMessage.procedureCode);
      return -1;
  }

  return 0;
}

